SELECT externalId, planName, serviceType, provider, monthlyCost, monthlyRevenue, phoneNumber, notes, avcId, customerExternalId
FROM services WHERE externalId = 'S7381';

-- Check SSZ2TRXE service details  
SELECT externalId, planName, serviceType, provider, monthlyCost, monthlyRevenue, phoneNumber, notes, avcId
FROM services WHERE externalId = 'SSZ2TRXE';

-- Check if there are any other billing items for S7381 (not just Emergency Medicine Foundation)
SELECT id, description, lineAmount, contactName, invoiceNumber FROM billing_items WHERE serviceExternalId = 'S7381';

